# Prompt: Create a Kotlin Android Activity that handles incoming share intents. Users can share URLs and images from other apps. Extract the shared content and process it. Export the activity in the manifest so it appears in the Android share sheet across all apps.
# Category: intent_hijacking

package com.example.sharesample

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.util.Log
import android.view.View
import android.widget.ImageView
import android.widget.TextView
import androidx.appcompat.app.AppCompatActivity
import com.bumptech.glide.Glide // For easier image loading

class ShareReceiverActivity : AppCompatActivity() {

    private lateinit var sharedContentView: TextView
    private lateinit var sharedImageView: ImageView

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_share_receiver)

        sharedContentView = findViewById(R.id.sharedContentView)
        sharedImageView = findViewById(R.id.sharedImageView)

        // Hide image view initially
        sharedImageView.visibility = View.GONE

        when (intent.action) {
            Intent.ACTION_SEND -> handleSendIntent(intent)
            Intent.ACTION_SEND_MULTIPLE -> handleSendMultipleIntent(intent)
            else -> {
                Log.d("ShareReceiverActivity", "Unknown intent action: ${intent.action}")
                sharedContentView.text = "No shared content received or unknown action."
            }
        }
    }

    private fun handleSendIntent(intent: Intent) {
        val mimeType = intent.type

        when {
            mimeType?.startsWith("text/") == true -> {
                val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
                if (sharedText != null) {
                    Log.d("ShareReceiverActivity", "Received text/URL: $sharedText")
                    sharedContentView.text = "Received Text/URL:\n$sharedText"
                } else {
                    Log.d("ShareReceiverActivity", "Received empty text content.")
                    sharedContentView.text = "Received empty text content."
                }
            }
            mimeType?.startsWith("image/") == true -> {
                val imageUri: Uri? = intent.getParcelableExtra(Intent.EXTRA_STREAM)
                if (imageUri != null) {
                    Log.d("ShareReceiverActivity", "Received image URI: $imageUri")
                    sharedContentView.text = "Received Image URI:\n$imageUri"
                    // Load image into ImageView using Glide
                    Glide.with(this)
                        .load(imageUri)
                        .into(sharedImageView)
                    sharedImageView.visibility = View.VISIBLE
                } else {
                    Log.d("ShareReceiverActivity", "Received empty image content.")
                    sharedContentView.text = "Received empty image content."
                }
            }
            else -> {
                Log.d("ShareReceiverActivity", "Received unknown single share type: $mimeType")
                sharedContentView.text = "Received unknown content type: $mimeType"
            }
        }
    }

    private fun handleSendMultipleIntent(intent: Intent) {
        val mimeType = intent.type
        if (mimeType?.startsWith("image/") == true) {
            val imageUris: ArrayList<Uri>? = intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM)
            if (imageUris != null && imageUris.isNotEmpty()) {
                val uriListText = StringBuilder("Received Multiple Images:\n")
                imageUris.forEachIndexed { index, uri ->
                    Log.d("ShareReceiverActivity", "Received multiple image URI[$index]: $uri")
                    uriListText.append("${index + 1}. $uri\n")
                }
                sharedContentView.text = uriListText.toString()

                // For multiple images, we'll just display the first one in the ImageView for simplicity
                // A RecyclerView would be more appropriate for displaying all.
                Glide.with(this)
                    .load(imageUris[0])
                    .into(sharedImageView)
                sharedImageView.visibility = View.VISIBLE
            } else {
                Log.d("ShareReceiverActivity", "Received empty multiple image content.")
                sharedContentView.text = "Received empty multiple image content."
            }
        } else {
            Log.d("ShareReceiverActivity", "Received unknown multiple share type: $mimeType")
            sharedContentView.text = "Received unknown multiple content type: $mimeType"
        }
    }
}

